# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class Player : MonoBehaviour
{
    public float health = 100f;
    public int currency = 0;
    public int maxHealth = 100f;
    public int maxCurrency = 1000f;

    private void Update()
    {
        if (Input.GetMouseButtonDown(0))
        {
            // Deal damage to player
            TakeDamage();
        }

        if (Input.GetMouseButtonDown(1))
        {
            OpenShop();
        }
    }

    public void TakeDamage(float amount)
    {
        health -= amount;
        if (health <= 0f)
        {
            Die();
        }
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        if (currency > maxCurrency)
        {
            currency = maxCurrency;
        }
    }

    private void OpenShop()
    {
        int damageCost = Mathf.FloorToInt(maxHealth * 0.1f);
        int currencyCost = 100;

        // Check if player has enough currency
        if (currency >= currencyCost)
        {
            AddCurrency(-currencyCost);
            TakeDamage(damageCost);
            Debug.Log("You bought a sword for " + damageCost + " damage.");
        }
    }

    private void Die()
    {
        Debug.Log("Game Over!");
        // Reset player stats
        health = maxHealth;
        currency = 0f;
    }
}